DROP TABLE IF EXISTS `zonelines`;
CREATE TABLE `zonelines` (
  `zonelineid` int(10) unsigned NOT NULL,
  `from_zone` smallint(3) unsigned NOT NULL DEFAULT 0,
  `from_pos_x` float(7,3) NOT NULL DEFAULT 0.000,
  `from_pos_y` float(7,3) NOT NULL DEFAULT 0.000,
  `from_pos_z` float(7,3) NOT NULL DEFAULT 0.000,
  `to_zone` smallint(3) unsigned NOT NULL DEFAULT 0,
  `to_pos_x` float(7,3) NOT NULL DEFAULT 0.000,
  `to_pos_y` float(7,3) NOT NULL DEFAULT 0.000,
  `to_pos_z` float(7,3) NOT NULL DEFAULT 0.000,
  `to_scale_x` float(7,3) NOT NULL DEFAULT 0.000,
  `to_scale_z` float(7,3) NOT NULL DEFAULT 0.000,
  `to_rotation` float(7,6) NOT NULL DEFAULT 0.000000,
  PRIMARY KEY (`zonelineid`)
) ENGINE=Aria TRANSACTIONAL=0 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

